from rouge_score import rouge_scorer

scorer = rouge_scorer.RougeScorer(['rougeL'], use_stemmer=True)

def is_duplicate(new_instruction: str,
                  existing_instructions: list[str],
                  threshold: float = 0.7) -> bool:
    """Return True if new_instruction is too similar to any existing one."""
    for existing in existing_instructions:
        score = scorer.score(new_instruction, existing)['rougeL'].fmeasure
        if score > threshold:
            return True
    return False


def build_instruction_pool(seed_tasks: list[dict],
                            target_size: int = 52000) -> list[dict]:
    pool = list(seed_tasks)
    existing_instructions = [t['instruction'] for t in pool]

    while len(pool) < target_size:
        new_tasks = generate_new_tasks(pool)
        for task in new_tasks:
            if not is_duplicate(task['instruction'], existing_instructions):
                pool.append(task)
                existing_instructions.append(task['instruction'])
            if len(pool) >= target_size:
                break
        print(f"Pool size: {len(pool)}")

    return pool
